# coding: utf-8
import warnings
from datetime import datetime, timedelta
from typing import List, TYPE_CHECKING

from rainbow_admin.errors import RainbowException
from rainbow_admin.release import Release

if TYPE_CHECKING:
    from rainbow_admin.admin import RainbowAdmin

CONFIG_TYPE_ENUM = {"GROUPCONFIG_KV": 0, "GROUPCONFIG_TABLE": 1, "GROUPCONFIG_FILE": 2}

CONFIG_TYPE_ENUM_REVERSE = {v: k for k, v in CONFIG_TYPE_ENUM.items()}

APPROVAL_PLUGINS = {
    "免审批插件": "li194myk-qmek-isjw-budf-vo8cgucisfqh",
    "review审批插件": "6z6fbh0b-yi7h-fu8s-apq1-2upswtlcfc38",
    "coding审批插件": "6dyhgfwr-qo2t-kzjf-dpc8-hzrtbvq1gpmz",
}


class BaseGroup(object):
    CONFIG_TYPE = 0

    def __init__(
        self,
        group_id=None,
        group_name=None,
        description="",
        config_type=0,
        admin: "RainbowAdmin" = None,
        **kwargs,
    ):
        self.admin = admin
        self.group_id = group_id
        self.group_name = group_name
        self.description = description

        if isinstance(config_type, str):
            config_type = CONFIG_TYPE_ENUM.get(config_type, 0)

        group_type = kwargs.get("group_type")
        is_public = kwargs.get("is_public")
        if is_public is not None:
            self.is_public = is_public
        if group_type is not None:
            self.is_public = group_type != "PRIVATE"
        self.config_type = config_type
        self.config_type_str = CONFIG_TYPE_ENUM_REVERSE[config_type]
        self.omit_approval = kwargs.get("omit_approval") or False
        self.publish_type = kwargs.get("publish_type", "DEFAULT")
        self.infos = kwargs

        self._cache = None

        if self.config_type != self.CONFIG_TYPE:
            raise ValueError(
                f"{self.__class__.__name__}只能实例化"
                f"config_type={CONFIG_TYPE_ENUM_REVERSE[self.config_type]}的group，"
                f"不能实例化config_type={self.config_type_str}的group"
            )

    @property
    def history_versions(self, size=9999, type=0):
        return self.admin.api.query_history_versions(self.group_id, size=size, type=type)

    def get_info(self, version_id=0, version_name=None):
        """
        :param version_id: 0为当前配置
        :param version_name: None 为当前配置
        :return:
        """
        if version_name:
            l = list(
                filter(lambda x: x['version_name'] == version_name, self.history_versions)
            )
            if len(l) == 0:
                raise RainbowException("历史版本中查不到指定的版本名 {verison_name}")
            if version_id and version_id != l[0]['version_id']:
                raise RainbowException("同时指定了version_id和version_name，但根据name查询到的id不一致 {verison_name}")
            version_id = l[0]['version_id']
        return self.admin.api.query_group_info(
            self.group_id, self.group_name, version_id
        )

    def update_group_setting_base(self, **kwargs):
        """更新分组设置

        :param description (str)
        :param enable_checksum (bool): True | False
        :param enable_configmap (bool): True | False
        :param is_host_publish (int): 是否开启主机发布，0：关闭，1：开启
        :param keep_ver (int <=30):  保留的版本数
        :param multi_version (int):  多版本发布，0：关闭，1：开启
        :param publish_type (str):  下发模式，Default | HOST
        """
        allow_setting = [
            'description',
            'enable_checksum',  # 是否开启 checksum
            'enable_configmap',
            # 'model_type',  # 审批模式，0：默认，1：review
            # 'omit_approval',  # 免审批，0：关闭，1：开启
            'keep_ver',
            'multi_version',  # 多版本发布，0：关闭，1：开启
            'is_host_publish',
            'publish_type',
        ]
        readonly_setting = [
            'enable_set',
            'is_unlimited_ver',
        ]
        # curr_settings = self.get_info()['group_info']
        curr_settings = self.admin.api.query_group_list(env_name=self.admin.env, group_name=self.group_name)[0]
        # 获取分组当前设定的选项，忽略不可改的系统选项
        settings = {k: curr_settings[k] for k in curr_settings if k in allow_setting or k in readonly_setting}
        settings.update({k: kwargs[k] for k in kwargs if k in allow_setting})

        return self.admin.api.change_group_setting(
            self.group_id,
            self.group_name,
            op_type=2,
            env_name=self.admin.env,
            **settings
        )

    @property
    def related_groups(self):
        return self.admin.api.query_related_groups(
            self.group_id, "PUBLIC" if self.is_public else "PRIVATE"
        )

    def update_info(self):
        self.infos = infos = self.get_info(0)["group_info"]
        self.config_type = CONFIG_TYPE_ENUM[infos["config_type"]]
        self.description = infos["description"]
        self.is_public = infos["group_type"] != "PRIVATE"

    def version_info(self, version_id):
        return self.get_info(version_id)["version_info"]

    @property
    def is_kv(self):
        return self.config_type == 0

    @property
    def is_table(self):
        return self.config_type == 1

    @property
    def is_file(self):
        return self.config_type == 2

    @property
    def permission_type(self):
        return self.infos.get("permission_type")

    @property
    def create_time(self):
        return self.infos.get("create_time")

    def create(self):
        if self.group_id:
            self.admin.api.update_group(
                self.group_id,
                self.group_name,
                self.description,
                self.is_public,
                self.config_type,
                self.omit_approval,
                env_name=self.admin.env,
            )
        else:
            new_group = self.admin.api.add_group(
                self.group_name,
                self.description,
                self.is_public,
                self.config_type,
                self.omit_approval,
                env_name=self.admin.env,
            )
            self.group_id = new_group["group_id"]
        return self

    def save(self):
        return self.create()

    def update_group(self, group_name=None, description=None, omit_approval=None):
        if group_name is not None:
            self.group_name = group_name
        if description is not None:
            self.description = description
        if omit_approval is not None:
            self.omit_approval = omit_approval
        self.save()

    def delete_group(self):
        if self.group_id:
            self.admin.api.delete_group(
                self.group_id, self.group_name, env_name=self.admin.env
            )
            self.group_id = None
            return True
        return False

    def relate_public_group(self, public_group: "BaseGroup"):
        """关联公共group"""
        assert not self.is_public
        assert public_group.is_public
        self.admin.api.relate_common(
            self.group_id, self.group_name, public_group.group_id
        )

    def cancel_relate(self, public_group: "BaseGroup"):
        """取消关联公共分组"""
        assert not self.is_public
        assert public_group.is_public
        self.admin.api.relate_common(
            self.group_id, self.group_name, public_group.group_id, is_add=False
        )

    def cancel_changes(self):
        return self.admin.api.cancel_changes(self.group_id, self.group_name)

    def query_client_list(self, start_time=None, end_time=None, size=10000, offset=0, client_tags=None):
        """查询分组客户端列表

        :param start_time: 起始时间
        :param end_time: 结束时间
        :param size: 单页条数，默认 10000
        :param offset: 分页数，默认 0
        :param client_tags: 按照dict结构的标识（标签）来筛选客户端列表, e.g., {"ip": "1.1.1.1", "set": "sh"}
        :return:
        """
        now = datetime.now()
        if not start_time:
            start_time = (now - timedelta(hours=2)).strftime('%Y-%m-%d %H:%M:%S')
        if not end_time:
            end_time = now.strftime('%Y-%m-%d %H:%M:%S')
        if client_tags is None:
            tags = []
        else:
            tags = [{"name": k, "value": client_tags[k]} for k in client_tags.keys()]
        rsp = self.admin.api.query_group_client_list(
            group_id=self.group_id,
            group_name=self.group_name,
            env_name=self.admin.env,
            start_time=start_time,
            end_time=end_time,
            size=size,
            offset=offset,
            client_tags=tags
        )
        return rsp
        # if not client_tags:
        #     return rsp
        # client_tags_list = [{"name": k, "value": client_tags[k]} for k in client_tags.keys()]
        # return list(
        #     filter(
        #         lambda x: all(
        #             tag in (list() if x['client_id'] == '' else x['client_id'])
        #             for tag in client_tags_list
        #         ),
        #         rsp
        #     )
        # )

    def query_version_distribute_rules(self):
        return self.admin.api.query_version_distribute_rules(
            env_name=self.admin.env,
            group_id=self.group_id,
            group_name=self.group_name,
        )

    def delete_version_distribute_rule(self, rule_id):
        return self.admin.api.delete_version_distribute_rule(
            env_name=self.admin.env,
            group_id=self.group_id,
            group_name=self.group_name,
            rule_id=rule_id,
        )

    def get_release_tasks(self, size=10) -> List[Release]:
        return self.admin.get_release_tasks(size, self.group_name)

    def create_release_task(
        self, creator, version_name=None, description="", updators="", approvers=None, type=0,
        multi_step_gray_contents=[]
    ):
        """创建发布任务

        :param creator: 提交人，api调用时请填写自定义用户对应的用户名（Rainbow_开头的命名）
        :param version_name: 本次修改要保存的版本名
        :param desc:
        :param approvers: 指定审批人，默认同 creator
        :param type: 审批方式，0：或签，1：会签
        :param updator: 校验配置项的修改人
        :param multi_step_gray_contents: 多步骤灰度规则
        :return: task_id
        """
        return self.admin.api.create_release_task(
            self.admin.env,
            self.group_id,
            self.group_name,
            creator,
            approvers,
            type,
            version_name,
            multi_step_gray_contents,
            description,
            updators
        )

    def create_multi_version_release_task(
        self, creator, version_name, target_tags='{}', desc='', approvers=None, type=0,
        multi_step_gray_contents=[]
    ):
        """在多版本发布功能下，创建发布任务，指定历史版本下发给 tags 组合的实例

        :param creator: 提交人，api调用时请填写自定义用户对应的用户名（Rainbow_开头的命名）
        :param version_name: 要发布的已保存的版本名
        :param target_tags: 目标实例的标签组合，json格式，{} 表示不限定标签。
                示例：{"city": "sz", "module": "httpapi"}。
        :param desc:
        :param approvers: 指定审批人，默认同 creator
        :param type: 审批方式，0：或签，1：会签
        :param updator: 校验配置项的修改人
        :param multi_step_gray_contents: 多步骤灰度规则
        """
        version_ids = list(filter(lambda x: x['version_name'] == version_name, self.history_versions))
        if not len(version_ids) == 1:
            raise RainbowException(f"cann't find version_id by version_name: {version_name}")
        if not approvers:
            approvers = creator
        return self.admin.api.create_release_task_v2(
            group_id=self.group_id,
            group_name=self.group_name,
            env_name=self.admin.env,
            cfg_version_id=version_ids[0]['version_id'],
            target_instance_tags=target_tags,
            description=desc,
            creator=creator,
            approvers=approvers,
            type=type,
            updators='',
            multi_step_gray_contents=multi_step_gray_contents,
        )

    def easy_release(
        self,
        creator="auto",
        version_name=None,
        description="",
        force_ignore_approval=False,
        updators="",
    ):
        """一键发布，要求开启分组的免审批功能

        :param creator: 版本创建人
        :param version_name: 版本名
        :param description: 版本描述
        :param force_ignore_approval: 自动开启免审批功能
        :param updators: 修改人，指定修改人时，会检查修改人，相当于页面上的 “只能有我的改动”
        :return:
        """
        warnings.warn(
            "easy_release is deprecated. please use one_click_release",
            DeprecationWarning,
        )
        if force_ignore_approval and not self.omit_approval:
            self.set_approval(False)
        task_id = self.create_release_task(creator, version_name, description, updators)
        release = self.admin.get_release_task(task_id)
        try:
            release.all_in()
        except RainbowException as e:
            raise RainbowException(
                "全量发布失败，请检查此分组是否开通免审批功能。"
                "可以通过 group.set_approval(False) 开启免审批或force_ignore_approval=True"
                f"{e}"
            )
        finally:
            release.close_task()
        return task_id

    def one_click_release(
        self,
        creator,
        approvers,
        updators,
        version_name=None,
        description="",
        force_ignore_approval=False,
        coding_plugin=None,
    ):
        """一键发布任务

        easy_release的单次调用版，避免easy_release的多次接口调用存在中间状态问题。如果是接口调用，
        则建议creator,approvers,updators都填接口“自定义用户”的用户名。

        PS: 注意使用本接口同样要开启分组的“发布免审批”功能

        :param creator: 发布人，需指定自定义用户名，且自定义用户要有发布权限
        :param approvers: 审批人
        :param updators: 检查文件的修改人，如果所有修改都是自定义用户，则填自定义用户，否则需要列全所有修改人
        :param version_name: 版本名
        :param description: 版本描述
        :param force_ignore_approval: 自动开启免审批功能
        :param coding_plugin: 可设置为2，当开启coding审批插件时，选择非现网变更，才可以跳过coding审批环节
        :return:
        """
        if force_ignore_approval and not self.omit_approval:
            self.set_approval(False)

        return self.admin.api.one_click_release_task(
            self.group_id,
            self.group_name,
            creator,
            updators,
            approvers,
            self.admin.env,
            version_name,
            description,
            coding_plugin=coding_plugin
        )

    def one_click_release_for_multi_version(
        self,
        creator,
        approvers,
        version_name=None,
        target_tags='{}',
        description="",
        force_ignore_approval=False,
        coding_plugin=None,
    ):
        """一键发布任务。建议 creator,approvers,updators 都填接口“自定义用户”的用户名。

        :param creator: 发布人，需指定自定义用户名，且自定义用户要有发布权限
        :param approvers: 审批人
        :param updators: 检查文件的修改人，如果所有修改都是自定义用户，则填自定义用户，否则需要列全所有修改人
        :param version_name: 版本名
        :param description: 版本描述
        :param force_ignore_approval: 自动开启免审批功能
        :param coding_plugin: True|False, 当开启coding审批插件时，选择非现网变更，才可以跳过coding审批环节
        :return:
        """
        version_ids = list(filter(lambda x: x['version_name'] == version_name, self.history_versions))
        if not len(version_ids) == 1:
            raise RainbowException(f"cann't find version_id by version_name: {version_name}")
        if force_ignore_approval and not self.omit_approval:
            self.set_approval(False)

        return self.admin.api.one_click_release_task_v2(
            self.group_id,
            self.group_name,
            creator,
            version_id=version_ids[0]['version_id'],
            target_instance_tags=target_tags,
            approvers=approvers,
            env_name=self.admin.env,
            description=description,
            coding_plugin=coding_plugin
        )

    def set_approval(self, need_approval: bool):
        """设置发布时是否需要审批

        :param need_approval: 需要审批为 True
        :return:
        """
        self.omit_approval = not need_approval
        self.save()

    def get_binded_plugins(self):
        """查询分组已绑定的插件
        """
        return self.admin.api.query_plugin_bind_info(self.group_id)

    def set_approval_plugin(
        self,
        name: str,
    ):
        """修改分组的审批插件

        :param  name: 可选值为：免审批插件 | review审批插件 | coding审批插件
        """
        if name not in APPROVAL_PLUGINS.keys():
            raise RainbowException(f"plugin name should be one of {'|'.join(APPROVAL_PLUGINS)}")

        rlt = self.get_binded_plugins()
        current_plugin = list(filter(lambda x: x['category'] == 9, rlt['bind_list']))
        if len(current_plugin) > 0:
            if current_plugin[0]['type_id'] == APPROVAL_PLUGINS[name]:
                return
            else:
                self.admin.api.group_plugin_bind(
                    'UNBIND',
                    self.group_id,
                    current_plugin[0]['type_id'],
                )
        return self.admin.api.group_plugin_bind('BIND', self.group_id, APPROVAL_PLUGINS[name])

    def set_approval_default(self):
        """重置分组的审批插件为默认值
        """
        rlt = self.get_binded_plugins()
        current_plugin = list(filter(lambda x: x['category'] == 9, rlt['bind_list']))
        if len(current_plugin) > 0:
            self.admin.api.group_plugin_bind(
                'UNBIND',
                self.group_id,
                current_plugin[0]['type_id'],
            )
        return

    def get_notice_set(self):
        return self.admin.api.query_notice_set(self.group_id)

    def change_notice_set(
        self,
        notice_type,
        chat_id,
        notice_status,
    ):
        notice_type_list = [
            "NOTICE_NONE",
            "NOTICE_ROBOT",
            "NOTICE_SRV"
        ]
        if notice_type not in notice_type_list:
            raise RainbowException(f"notice_type should be one of {notice_type_list}")

        notice_status_list = [
            "MAIN_RELEASE",
            "ROLLBACK",
            "GRAY_RELEASE",
            "APPROVAL_REJECT",
            "WAIT_RELEASE",
            "WAIT_APPROVAL"
        ]
        if notice_status is not None \
                and len(set(notice_status.split(";")) - set(notice_status_list)) > 0:
            raise RainbowException(f"notice_status should be subset of {';'.join(notice_status_list)}")

        notice = self.get_notice_set()
        return self.admin.api.change_notice_set(
            self.group_id,
            notice_type=notice_type,
            chat_id=chat_id if chat_id is not None else notice['chat_id'],
            notice_status=notice_status if notice_status is not None else notice['notice_status'],
        )

    def create_config_version(self, creator, version_name=None, updators="", version_desc="", tpl_version="", enable_extra_file=True):
        """
        版本生成和版本发布分离时，创建配置版本（但不发布）

        :param  creator:
        :param  version_name: 版本名
        :param  updators
        :param  version_desc
        :param  tpl_version: 关联的通用模板的版本号
        :param  extra_as_file: 多余的变量直接生成文件
        """
        if not version_name:
            now = datetime.now().strftime("%Y%m%d%H%M%S%f")[:14]
            version_name = f"v_{now}_release"
        return self.admin.api.create_config_version(
            self.admin.env,
            group_id=self.group_id,
            group_name=self.group_name,
            version_name=version_name,
            version_desc=version_desc,
            creator=creator,
            updators=updators,
            tpl_version=tpl_version,
            enable_extra_file=enable_extra_file
        )

    def query_config_data(self, version_name, size=100, offset=0):
        """
        获取指定版本的配置内容。这个api封装了 普通kv型、kv+模板、分set的kv+模板 几种用法下，统一获取历史版本内容

        :param  group_name
        :param  env_name
        :param  version_name
        :param  size
        :param  offset
        """
        return self.admin.api.query_config_data(
            group_name=self.group_name,
            env_name=self.admin.env,
            version_name=version_name,
            size=size,
            offset=offset
        )

    def clear_cache(self):
        self._cache = None

    def __str__(self) -> str:
        return f"{self.__class__.__name__}(group_id={self.group_id},group_name={self.group_name}),env={self.admin.env}"

    __repr__ = __str__
